import{_ as a,o as s,c as e,a0 as p}from"./chunks/framework.jwovEGr5.js";const r="/assets/001_video-work-is-hard_Jn32bhqaho.rwnFXEX8.png",o="/assets/002_two-ai-video-teams_SXcUb9mpMo.Cf53uCRv.png",n="/assets/003_summon-expert-team-pc_FHrNbNCiBo.C_dD-dni.png",d="/assets/004_video-team-roles_ZOJ8b7aQ7o.lfmhenYQ.png",i="/assets/005_multi-agent-team-overview_NzPHbTGH2o.BFWkpQ9m.png",l="/assets/006_hyperframes-engine_Uj4hbc6Tzo.CYZFNQ_m.png",h="/assets/007_collection-report_KPn1bXgYQo.DsCyZHHa.png",c="/assets/008_planner-full_YPM3boyNTo.CHx0xrr_.png",_="/assets/009_video-producer_PohnbE1jKo.CmEbaTj1.png",m="/assets/010_workbuddy-flow_FSJzb5xLQo.dELsALQx.png",b="/assets/011_publish-demo_DdTYbbBxLo.D7gtoNGq.png",g="/assets/012_publish-result_Qpz2bvBwTo.CwRG5daz.png",u="/assets/013_anatomy-team_OI1Ubltu1o.Cf-1Sb2N.png",f="/assets/014_anatomy-demo_PJuybCsQao.C8hzZ1I-.png",x="/assets/015_anatomy-flow_CuFcbaM9Ao.C38u0uIQ.png",y="/assets/016_audio-extract_EijVbt25mo.DyXCB_MA.png",q="/assets/017_transcript-result_Zyc0bjAhTo.B390CAR4.png",P="/assets/018_video-understand_VwxLb62b1o.CTpGVkMH.png",k="/assets/019_clip-cut_HAWrbELZIo.J0Dd9-U_.png",S=JSON.parse('{"title":"第 19 章 一句话召唤 AI 视频团队 ​","description":"","frontmatter":{},"headers":[],"relativePath":"p2/19.md","filePath":"p2/19.md"}'),v={name:"p2/19.md"};function C(A,t,T,I,B,H){return s(),e("div",null,[...t[0]||(t[0]=[p('<h1 id="第-19-章-一句话召唤-ai-视频团队-​" tabindex="-1">第 19 章 一句话召唤 AI 视频团队 ​ <a class="header-anchor" href="#第-19-章-一句话召唤-ai-视频团队-​" aria-label="Permalink to &quot;第 19 章 一句话召唤 AI 视频团队 ​&quot;">​</a></h1><p>在 WorkBuddy 里把短视频工作拆成两支 AI 专家团：一支负责自动生产视频，一支负责拆解爆款视频。</p><p><img src="'+r+'" alt=""></p><table tabindex="0"><thead><tr><th>团队</th><th>负责什么</th><th>适合什么任务</th></tr></thead><tbody><tr><td><strong>视频生成团队</strong></td><td>从主题出发，完成热点采集、选题筛选、脚本、分镜、配音、渲染、字幕和发布。</td><td>AI 周报、产品更新、知识科普、行业分析、产品评测。</td></tr><tr><td><strong>爆款视频拆解团队</strong></td><td>从视频链接出发，下载视频、提取音频、转写文案、分析镜头语言，生成拆解报告和仿拍建议。</td><td>学习爆款结构、复盘竞品视频、沉淀拍摄手册、给生成团队提供参考。</td></tr></tbody></table><p>这两个团队并不是互相替代的关系。视频生成团队解决“今天怎么做一条出来”，爆款拆解团队解决“为什么别人那条能火，我能学到什么”。一个负责生产，一个负责学习，组合起来才有持续迭代的可能。</p><p><img src="'+o+'" alt=""></p><h2 id="如何召唤-从一句话开始-但不要停在一句话-​" tabindex="-1">如何召唤：从一句话开始，但不要停在一句话 ​ <a class="header-anchor" href="#如何召唤-从一句话开始-但不要停在一句话-​" aria-label="Permalink to &quot;如何召唤：从一句话开始，但不要停在一句话 ​&quot;">​</a></h2><p><img src="'+n+'" alt=""></p><p>text</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>召唤视频生成团队，制作一条 46 秒 AI 周报短视频。</span></span></code></pre></div><h2 id="第一支团队-视频生成团队-​" tabindex="-1">第一支团队：视频生成团队 ​ <a class="header-anchor" href="#第一支团队-视频生成团队-​" aria-label="Permalink to &quot;第一支团队：视频生成团队 ​&quot;">​</a></h2><p>视频生成团队里有四个核心角色：视频生成团队主理人凌导、信息采集员灵阅、内容策划师灵枢、视频制作师灵映。它们不是四个换名字的聊天窗口，而是一条有上下游交接关系的视频生产线。</p><p><img src="'+d+'" alt=""></p><table tabindex="0"><thead><tr><th>角色</th><th>定位</th><th>交付物</th></tr></thead><tbody><tr><td>凌导</td><td>主理人 / 团长</td><td>拆解任务、安排并行与串行流程、汇总产物、处理检查点。</td></tr><tr><td>灵阅</td><td>信息采集员</td><td>热点池、来源表、去重后的结构化摘要、选题候选。</td></tr><tr><td>灵枢</td><td>内容策划师</td><td>选题判断、脚本、分镜、旁白、转场、素材清单、BGM 和字幕节奏。</td></tr><tr><td>灵映</td><td>视频制作师</td><td>HTML 视频工程、配音、字幕对齐、转场动画、素材拼接、渲染成片。</td></tr></tbody></table><p>这才是多 Agent 的关键：不是角色越多越好，而是每个角色都有清晰输入和输出。信息采集员不直接写成片脚本，策划师不重新编造热点，制作师不重写事实，团长负责让流程不断档。</p><p><img src="'+i+'" alt=""></p><h3 id="底层生产引擎-hyperframes-​" tabindex="-1">底层生产引擎：HyperFrames ​ <a class="header-anchor" href="#底层生产引擎-hyperframes-​" aria-label="Permalink to &quot;底层生产引擎：HyperFrames ​&quot;">​</a></h3><p>文章提到，这条视频流水线基于 HyperFrames 搭建。它的核心思路是用 HTML 渲染视频，天然适合 Agent 生成结构化工程，再交给渲染工具输出 MP4。它还带有 CLI 工具链、TTS、字幕、去背景和视频组件模板。</p><p><img src="'+l+'" alt=""></p><h3 id="生成流程一-信息采集员先让热点有来源-​" tabindex="-1">生成流程一：信息采集员先让热点有来源 ​ <a class="header-anchor" href="#生成流程一-信息采集员先让热点有来源-​" aria-label="Permalink to &quot;生成流程一：信息采集员先让热点有来源 ​&quot;">​</a></h3><p>做视频最耗时间的往往不是剪辑，而是“今天到底拍什么”。所以视频生成团队先让信息采集员灵阅抓 RSS、搜新闻、扫社媒、聚合 AI 热点，并去重输出结构化摘要。</p><p><img src="'+h+'" alt=""></p><p>这个阶段的产物至少应该包含：标题、来源、发布时间、事件发生时间、原始链接、热度线索、为什么值得关注。热度只能帮助排序，不能替代事实核验。</p><h3 id="生成流程二-内容策划师把主题变成镜头-​" tabindex="-1">生成流程二：内容策划师把主题变成镜头 ​ <a class="header-anchor" href="#生成流程二-内容策划师把主题变成镜头-​" aria-label="Permalink to &quot;生成流程二：内容策划师把主题变成镜头 ​&quot;">​</a></h3><p>选题有了之后，真正费脑子的是“这条视频怎么讲”。内容策划师灵枢负责选题评估、脚本写作、分镜设计、旁白文案、镜头节奏，以及转场建议、素材清单、BGM 节奏、字幕停顿和情绪节点。</p><p><img src="'+c+'" alt=""></p><p>这里建议设置第一次人工检查：开头 3 秒是否有钩子，46 秒是否塞入过多信息，旁白是否准确，画面是否真的支撑观点。脚本不过关时，不要进入配音和渲染。</p><h3 id="生成流程三-视频制作师把分镜变成成片-​" tabindex="-1">生成流程三：视频制作师把分镜变成成片 ​ <a class="header-anchor" href="#生成流程三-视频制作师把分镜变成成片-​" aria-label="Permalink to &quot;生成流程三：视频制作师把分镜变成成片 ​&quot;">​</a></h3><p>灵映会把确认后的脚本转成 HTML，再调用 HyperFrames 渲染 MP4。文章里提到，系统会自动完成 Azure TTS 配音、Whisper 字幕对齐、动画与转场生成、素材拼接、字幕叠加和视频渲染。</p><p><img src="'+_+'" alt=""></p><p><img src="'+m+'" alt=""></p><p>成片验收不要只看“能不能播放”。至少检查旁白与字幕是否一致、镜头时长是否匹配、文字是否遮挡主体、BGM 是否可用、素材是否有版权风险、画面是否适合目标平台安全区。</p><h3 id="生成流程四-发布可以自动化-但默认要人工确认-​" tabindex="-1">生成流程四：发布可以自动化，但默认要人工确认 ​ <a class="header-anchor" href="#生成流程四-发布可以自动化-但默认要人工确认-​" aria-label="Permalink to &quot;生成流程四：发布可以自动化，但默认要人工确认 ​&quot;">​</a></h3><p>发布 Agent 自动生成标题、自动打标签、自动上传封面，并通过云手机发布到抖音、视频号和 B 站。这是很强的自动化能力，但蓝皮书建议默认不要直接自动发布，除非账号、素材、标题和合规边界都已经过人工确认。</p><p><img src="'+b+'" alt=""></p><p><img src="'+g+'" alt=""></p><h2 id="第二支团队-爆款视频拆解团队-​" tabindex="-1">第二支团队：爆款视频拆解团队 ​ <a class="header-anchor" href="#第二支团队-爆款视频拆解团队-​" aria-label="Permalink to &quot;第二支团队：爆款视频拆解团队 ​&quot;">​</a></h2><p>光会生成还不够。</p><p>内容创作者真正需要的是理解“为什么别人能爆”，把一条爆款视频拆成可以参考的操作手册：提取视频、转录文案、分析景别运镜、剪辑节奏、色调风格，并给出仿拍建议。</p><p><img src="'+u+'" alt=""></p><p><img src="'+f+'" alt=""></p><table tabindex="0"><thead><tr><th>角色</th><th>职责</th><th>工具 / 技术</th></tr></thead><tbody><tr><td>阿爆</td><td>团长 / 拆解总控</td><td>任务调度、流程编排、结果汇总。</td></tr><tr><td>小凯</td><td>音频处理与转录</td><td>ffmpeg、ASR，把视频音频转成完整口播文案。</td></tr><tr><td>小淼</td><td>视频理解与镜头裁切</td><td>视频理解 API、ffmpeg，分析镜头语言并裁切片段。</td></tr></tbody></table><h3 id="拆解流程一-视频下载要有降级策略-​" tabindex="-1">拆解流程一：视频下载要有降级策略 ​ <a class="header-anchor" href="#拆解流程一-视频下载要有降级策略-​" aria-label="Permalink to &quot;拆解流程一：视频下载要有降级策略 ​&quot;">​</a></h3><p>爆款拆解的第一步是拿到视频。文章里专门提到，最复杂的是视频下载，所以设计了一套三层降级策略：官方 API、Playwright、yt-dlp。只要有一层成功，流程就继续。</p><p><img src="'+x+'" alt=""></p><p>这里必须加上边界：视频下载和分析要遵守平台条款、版权授权和合理使用范围。拆解的目的应该是学习结构和方法，不是搬运原视频。</p><h3 id="拆解流程二-音频提取与文案转写-​" tabindex="-1">拆解流程二：音频提取与文案转写 ​ <a class="header-anchor" href="#拆解流程二-音频提取与文案转写-​" aria-label="Permalink to &quot;拆解流程二：音频提取与文案转写 ​&quot;">​</a></h3><p>视频下载完成后，小凯用 ffmpeg 提取音频，把 video.mp4 转成 audio.mp3，再调用语音识别 API 自动转录完整口播文案。以前一句句听、一句句敲的工作，现在可以被稳定自动化。</p><p><img src="'+y+'" alt=""></p><p><img src="'+q+'" alt=""></p><h3 id="拆解流程三-视频理解与镜头语言分析-​" tabindex="-1">拆解流程三：视频理解与镜头语言分析 ​ <a class="header-anchor" href="#拆解流程三-视频理解与镜头语言分析-​" aria-label="Permalink to &quot;拆解流程三：视频理解与镜头语言分析 ​&quot;">​</a></h3><p>接下来是最有意思的一步：视频理解。小淼会分析整条视频的景别、运镜、转场、剪辑节奏、色调、镜头时长。很多看起来“有感觉”的爆款视频，背后其实有稳定的镜头规律。</p><p><img src="'+P+'" alt=""></p><p><img src="'+k+`" alt=""></p><h2 id="两支团队如何形成闭环-​" tabindex="-1">两支团队如何形成闭环 ​ <a class="header-anchor" href="#两支团队如何形成闭环-​" aria-label="Permalink to &quot;两支团队如何形成闭环 ​&quot;">​</a></h2><p>两个专家团可以合作。先用爆款拆解团队学习镜头语言和节奏，再让视频生成团队生产新视频，发布之后继续分析数据，再反过来优化下一版内容。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>flowchart LR</span></span>
<span class="line"><span>    A[爆款视频链接] --&gt; B[拆解团队：转写、镜头、节奏、仿拍建议]</span></span>
<span class="line"><span>    B --&gt; C[形成拍摄手册和内容规律]</span></span>
<span class="line"><span>    C --&gt; D[生成团队：热点、脚本、分镜、渲染]</span></span>
<span class="line"><span>    D --&gt; E[人工验收与发布]</span></span>
<span class="line"><span>    E --&gt; F[数据复盘]</span></span>
<span class="line"><span>    F --&gt; B</span></span></code></pre></div><p>这就是专家团比单个工具更有意义的地方。它不只是帮你做一条视频，而是让“学习、生产、发布、复盘”变成一个可以重复运转的系统。</p>`,58)])])}const w=a(v,[["render",C]]);export{S as __pageData,w as default};
